import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { PieChart, Pie, Cell, Tooltip, Legend } from 'recharts';

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#e91e63', '#9c27b0', '#3f51b5', '#4caf50', '#ff9800', '#795548', '#607d8b', '#f44336'];

const CommandeStats = () => {
  const [data, setData] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:3001/commandes')
      .then(res => {
        const commandes = res.data;

        // Compter les commandes par mois
        const counts = {};

        commandes.forEach(cmd => {
          const date = new Date(cmd.dateCommande); // adapte ce champ si différent
          const month = date.toLocaleString('default', { month: 'long' });
          counts[month] = (counts[month] || 0) + 1;
        });

        // Convertir en tableau pour Recharts
        const formatted = Object.entries(counts).map(([month, value]) => ({
          name: month,
          value,
        }));

        setData(formatted);
      })
      .catch(err => console.error("Erreur chargement des commandes :", err));
  }, []);

  return (
    <div style={{ textAlign: 'center' }}>
      <h3>Commandes par Mois</h3>
      <PieChart width={400} height={400}>
        <Pie
          data={data}
          cx="50%"
          cy="50%"
          labelLine={false}
          label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
          outerRadius={150}
          fill="#8884d8"
          dataKey="value"
        >
          {data.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
          ))}
        </Pie>
        <Tooltip />
        <Legend />
      </PieChart>
    </div>
  );
};

export default CommandeStats;
